import { BedrockAgentRuntimeClient, InvokeAgentCommand } from '@aws-sdk/client-bedrock-agent-runtime';
import { VexClient } from 'vex-sdk';

const bedrock = new BedrockAgentRuntimeClient({ region: 'us-gov-west-1' });
const vex = new VexClient({ apiKey: 'your-vex-api-key' });

async function invokeGovAgent(
  agentId: string,
  sessionId: string,
  input: string
): Promise<any> {
  const command = new InvokeAgentCommand({
    agentId,
    agentAliasId: 'latest',
    sessionId,
    inputText: input
  });

  const response = await bedrock.send(command);

  // Verify session continuity and compliance
  const verification = await vex.verify({
    input,
    output: response.completion,
    sessionId,
    policies: ['FISMA-AI-EXPLAINABILITY', 'EO-AI-APPEALABLE'],
    context: { classification: 'UNCLASSIFIED//FOUO' }
  });

  if (!verification.passed) {
    throw new Error(`Gov compliance violation: ${JSON.stringify(verification.violations)}`);
  }

  return response;
}

